//! Spec-compliance tests: Tab Stops (ISO 29500-1 §17.3.1.38)
//!
//! These tests verify our implementation against specific OOXML tab stop
//! constructs. Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{InlineNode, TabAlignment, TabLeader};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/tabs";

// ── direct tab stops ─────────────────────────────────────────────────────

/// ISO 29500-1 §17.3.1.38: Explicit tab stops with different alignments and leaders.
///
/// Fixture has tab stops at: left@1440, center@4320, right@7200 (dot leader).
/// Tab stops ARE fully parsed into ParagraphNode.tab_stops.
#[test]
fn spec_direct_tab_stops_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "direct-tabs");
    let paras = common::all_paragraphs(&doc);

    // Find the paragraph with tab stops (skip any default empty paragraphs)
    let p = paras.iter().find(|p| !p.tab_stops.is_empty()).expect(
        "should find a paragraph with tab stops. \
             The fixture has explicit w:tabs but tab_stops is empty on all paragraphs.",
    );

    // Should have at least the 3 explicit stops (synthesized stops may be added for extra tabs)
    assert!(
        p.tab_stops.len() >= 3,
        "expected at least 3 tab stops (left@1440, center@4320, right@7200), got {}",
        p.tab_stops.len()
    );

    // Note: tab stop positions in the domain model may be adjusted from absolute
    // page-margin positions to paragraph-edge-relative positions. We check for the
    // correct alignments and that positions are in ascending order.
    let alignments: Vec<&TabAlignment> = p.tab_stops.iter().map(|s| &s.alignment).collect();
    assert!(
        alignments.contains(&&TabAlignment::Left),
        "should have a left-aligned tab stop, got alignments: {:?}",
        alignments
    );
    assert!(
        alignments.contains(&&TabAlignment::Center),
        "should have a center-aligned tab stop, got alignments: {:?}",
        alignments
    );
    assert!(
        alignments.contains(&&TabAlignment::Right),
        "should have a right-aligned tab stop, got alignments: {:?}",
        alignments
    );

    // Check that the right tab at position 7200 has a dot leader
    let right_stop = p
        .tab_stops
        .iter()
        .find(|s| s.alignment == TabAlignment::Right)
        .expect("should have a right-aligned stop");
    assert_eq!(
        right_stop.leader,
        Some(TabLeader::Dot),
        "right tab stop should have dot leader, got: {:?}",
        right_stop.leader
    );

    // Positions should be in ascending order
    for pair in p.tab_stops.windows(2) {
        assert!(
            pair[0].position <= pair[1].position,
            "tab stops should be in ascending order, but {} > {}",
            pair[0].position,
            pair[1].position
        );
    }
}

// ── style-inherited tabs ─────────────────────────────────────────────────

/// ISO 29500-1 §17.3.1.38 + §17.7: Tab stops inherited from paragraph style.
///
/// Style "TabStyle" defines tabs at 720 (left) and 3600 (center).
/// The paragraph using TabStyle should inherit these stops.
///
/// These resolution/synthesis tests read `effective_tab_stops_rel` (the
/// style-resolved, default-grid-synthesized view value): `tab_stops` holds
/// only the paragraph's own authored pPr stops after the authored/effective
/// split (see spec_direct_tab_stops_parsed for the authored side).
#[test]
fn spec_style_inherited_tabs() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "style-inherited-tabs");
    let paras = common::all_paragraphs(&doc);

    // Find the paragraph that uses TabStyle
    let p = paras
        .iter()
        .find(|p| p.style_id.as_deref() == Some("TabStyle"))
        .expect(
            "should find a paragraph with style_id='TabStyle'. \
             The fixture applies this style but it may not have survived import.",
        );

    assert!(
        !p.effective_tab_stops_rel.is_empty(),
        "paragraph with TabStyle should inherit tab stops from the style, \
         but tab_stops is empty. Style tab inheritance may not be working.",
    );

    // Should have at least the 2 style-defined stops
    assert!(
        p.effective_tab_stops_rel.len() >= 2,
        "expected at least 2 inherited tab stops (720 left, 3600 center), got {}",
        p.effective_tab_stops_rel.len()
    );

    let alignments: Vec<&TabAlignment> = p
        .effective_tab_stops_rel
        .iter()
        .map(|s| &s.alignment)
        .collect();
    assert!(
        alignments.contains(&&TabAlignment::Left),
        "inherited stops should include a left stop, got: {:?}",
        alignments
    );
    assert!(
        alignments.contains(&&TabAlignment::Center),
        "inherited stops should include a center stop, got: {:?}",
        alignments
    );
}

// ── clear tab stop ───────────────────────────────────────────────────────

/// ISO 29500-1 §17.3.1.38: "clear" tab entry removes an inherited stop.
///
/// Style defines tabs at 1440 and 2880. Paragraph clears the stop at 1440.
/// Effective tabs should only include 2880. The clear OVERLAY is a cascade
/// result (derived `effective_tab_stops_rel`); the authored `tab_stops` keeps
/// the paragraph's own `val="clear"` entry verbatim so it re-serializes.
#[test]
fn spec_clear_tab_stop_semantics() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "clear-tab-stop");
    let paras = common::all_paragraphs(&doc);

    // Find the paragraph with ClearTabStyle
    let p = paras
        .iter()
        .find(|p| p.style_id.as_deref() == Some("ClearTabStyle"))
        .expect("should find a paragraph with style_id='ClearTabStyle'");

    // Authored side: the paragraph's own w:tabs (the val="clear" entry at
    // 1440) is preserved verbatim in `tab_stops`.
    assert!(
        p.tab_stops
            .iter()
            .any(|s| s.position == 1440 && s.alignment == TabAlignment::Clear),
        "the authored val='clear' entry at 1440 must survive in tab_stops verbatim, got: {:?}",
        p.tab_stops
            .iter()
            .map(|s| (s.position, &s.alignment))
            .collect::<Vec<_>>()
    );

    // The stop at position 1440 should be cleared; only 2880 should remain
    // (plus any synthesized default stops for the tab characters in text).
    let has_1440 = p.effective_tab_stops_rel.iter().any(|s| s.position == 1440);
    assert!(
        !has_1440,
        "tab stop at position 1440 should have been cleared by val='clear', \
         but it still appears in effective tab_stops: {:?}",
        p.effective_tab_stops_rel
            .iter()
            .map(|s| (s.position, &s.alignment))
            .collect::<Vec<_>>()
    );

    // The 2880 stop should still be present (positions may be adjusted to
    // paragraph-edge-relative, so check that at least one stop has the right
    // alignment from position 2880).
    let has_right_stop = p
        .effective_tab_stops_rel
        .iter()
        .any(|s| s.alignment == TabAlignment::Right);
    assert!(
        has_right_stop,
        "tab stop at position 2880 (right) should survive after clearing 1440, \
         but no right-aligned stop found in: {:?}",
        p.effective_tab_stops_rel
            .iter()
            .map(|s| (s.position, &s.alignment))
            .collect::<Vec<_>>()
    );
}

// ── default tab interval ─────────────────────────────────────────────────

/// ISO 29500-1 §17.15.1.25: Custom defaultTabStop from settings.xml.
///
/// Document has defaultTabStop=360 (0.25 inch). Paragraph has 3 tab characters
/// and no explicit stops, so synthesized stops should be at 360, 720, 1080.
/// Synthesis is a derived-view concern (`effective_tab_stops_rel`); the
/// authored `tab_stops` stays empty — synthesized stops must never be
/// serialized as if the author wrote them.
#[test]
fn spec_default_tab_interval_from_settings() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "default-tab-interval");
    let paras = common::all_paragraphs(&doc);

    // Find a paragraph with tab stops (synthesized from default interval)
    let p = paras
        .iter()
        .find(|p| !p.effective_tab_stops_rel.is_empty())
        .expect(
            "should find a paragraph with synthesized tab stops. \
             The fixture has tabs in text and defaultTabStop=360 in settings.xml, \
             but no stops were synthesized. The custom defaultTabStop may not \
             have survived the python-docx save.",
        );

    // With defaultTabStop=360 and text "A\tB\tC\tD" (3 tabs), we expect
    // synthesized stops at 360-twip intervals.
    assert!(
        p.effective_tab_stops_rel.len() >= 3,
        "expected at least 3 synthesized tab stops for 3 tab characters, got {}",
        p.effective_tab_stops_rel.len()
    );

    // Verify the interval: difference between consecutive positions should be 360
    if p.effective_tab_stops_rel.len() >= 2 {
        let interval =
            p.effective_tab_stops_rel[1].position - p.effective_tab_stops_rel[0].position;
        assert_eq!(
            interval, 360,
            "synthesized tab stop interval should be 360 twips (from defaultTabStop=360), \
             got interval of {} between positions {} and {}",
            interval, p.effective_tab_stops_rel[0].position, p.effective_tab_stops_rel[1].position
        );
    }
}

// ── ptab widget ──────────────────────────────────────────────────────────

/// ISO 29500-1 §17.3.3.22: w:ptab produces an opaque inline widget.
///
/// The positioned tab element should be preserved as an OpaqueInline
/// (not collapsed into text or ignored).
#[test]
fn spec_ptab_produces_opaque_inline() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "ptab-widget");
    let paras = common::all_paragraphs(&doc);

    // Find the paragraph containing the ptab (should have an OpaqueInline)
    let has_opaque = paras.iter().any(|p| {
        let inlines = p.all_inlines_owned();
        inlines
            .iter()
            .any(|i| matches!(i, InlineNode::OpaqueInline(_)))
    });

    assert!(
        has_opaque,
        "should find an OpaqueInline in the paragraph containing w:ptab. \
         The ptab element should be treated as a widget, not collapsed or ignored. \
         Paragraphs found: {}",
        paras.len()
    );
}
